def solar_term_correction_minutes(year: int, index: int) -> int:
    result = 0
    if SOLAR_TERM_DATA_MIN_YEAR <= year <= SOLAR_TERM_DATA_MAX_YEAR:
        position = (year - SOLAR_TERM_DATA_MIN_YEAR) * 24 + index
        result = ALPHABET.index(PACKED[position]) - OFFSET
    return result
